import java.io.*;import java.util.*;class Main{static String r(String s,int k){if(k<=1)return s;int[]c=new int[26],last=new int[26];Arrays.fill(last,-1000000000);for(char ch:s.toCharArray())c[ch-'a']++;StringBuilder out=new StringBuilder();for(int p=0;p<s.length();p++){int b=-1;for(int i=0;i<26;i++)if(c[i]>0&&p-last[i]>=k&&(b<0||c[i]>c[b]))b=i;if(b<0)return"";out.append((char)('a'+b));c[b]--;last[b]=p;}return out.toString();}public static void main(String[]a)throws Exception{String[]d=new String(System.in.readAllBytes()).trim().split("\\s+");if(d.length==1&&d[0].isEmpty())return;int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){String s=d[idx++];int k=Integer.parseInt(d[idx++]);if(tc>0)out.append("\n\n");out.append('"').append(r(s,k)).append('"');}System.out.print(out);}}
